import React, { useState, useEffect } from 'react';
import { api } from '../../contexts/AuthContext';
import ConfirmDialog from '../../components/ConfirmDialog';

const AdminScraper = () => {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [scrapedVideos, setScrapedVideos] = useState([]);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [selectedSite, setSelectedSite] = useState('91p');
  const [previewVideo, setPreviewVideo] = useState(null);
  const [confirmDialog, setConfirmDialog] = useState({
    isOpen: false,
    type: 'danger',
    title: '',
    message: '',
    onConfirm: null
  });
  const [hlsInstance, setHlsInstance] = useState(null);
  const [selectedVideos, setSelectedVideos] = useState([]);
  const [selectAll, setSelectAll] = useState(false);

  // 处理HLS视频播放和iframe预览
  useEffect(() => {
    // 判断是否是iframe URL（包含embed或91等关键字）
    const isIframeUrl = previewVideo && previewVideo.video_url && 
                        (previewVideo.video_url.includes('embed') || 
                         previewVideo.video_url.includes('91'));

    if (previewVideo && previewVideo.video_url && previewVideo.video_url.includes('.m3u8')) {
      // 动态加载HLS.js
      const loadHls = () => {
        if (!window.Hls) {
          const script = document.createElement('script');
          script.src = 'https://cdn.jsdelivr.net/npm/hls.js@latest';
          script.onload = () => {
            console.log('HLS.js loaded');
            initializeHls();
          };
          script.onerror = () => {
            console.error('Failed to load HLS.js');
          };
          document.head.appendChild(script);
        } else {
          initializeHls();
        }
      };

      // 延迟加载，确保DOM已准备好
      const timer = setTimeout(loadHls, 100);
      return () => clearTimeout(timer);
    }
  }, [previewVideo]);

  const initializeHls = () => {
    const videoElement = document.querySelector('#preview-video');
    if (videoElement && window.Hls && previewVideo.video_url) {
      try {
        console.log('Initializing HLS with URL:', previewVideo.video_url);
        const hls = new window.Hls({
          debug: true,
          enableWorker: true,
          lowLatencyMode: true,
          backBufferLength: 90,
          maxBufferLength: 600,
          maxMaxBufferLength: 1200,
        });

        hls.loadSource(previewVideo.video_url);
        hls.attachMedia(videoElement);

        hls.on(window.Hls.Events.MEDIA_ATTACHED, function() {
          console.log('HLS media attached');
          // 延迟一点时间确保视频元素准备好
          setTimeout(() => {
            videoElement.play().then(() => {
              console.log('HLS autoplay successful');
            }).catch((error) => {
              console.log('HLS autoplay failed:', error);
            });
          }, 100);
        });

        hls.on(window.Hls.Events.MANIFEST_PARSED, function() {
          console.log('HLS manifest loaded successfully');
        });

        hls.on(window.Hls.Events.FRAG_LOADED, function() {
          console.log('HLS fragment loaded');
        });

        hls.on(window.Hls.Events.ERROR, function(event, data) {
          console.error('HLS error:', event, data);
          if (data.fatal) {
            console.error('Fatal HLS error, falling back to cover');
            // 隐藏加载指示器
            const loadingElement = document.getElementById('video-loading');
            if (loadingElement) {
              loadingElement.style.display = 'none';
            }
            // 如果HLS失败，显示封面
            if (previewVideo.cover_url) {
              videoElement.style.display = 'none';
              const img = document.createElement('img');
              img.src = previewVideo.cover_url;
              img.alt = previewVideo.title;
              img.className = 'absolute inset-0 w-full h-full object-cover';
              videoElement.parentNode.appendChild(img);
            }

            // HLS加载失败，已显示封面
            console.log('HLS error, fallback to cover image');
          }
        });

        hls.on(window.Hls.Events.FRAG_LOADED, function() {
          // 隐藏加载指示器
          const loadingElement = document.getElementById('video-loading');
          if (loadingElement) {
            loadingElement.style.display = 'none';
          }
        });

        hls.on(window.Hls.Events.MANIFEST_PARSED, function() {
          // 隐藏加载指示器
          const loadingElement = document.getElementById('video-loading');
          if (loadingElement) {
            loadingElement.style.display = 'none';
          }
        });
      } catch (error) {
        console.error('Error initializing HLS:', error);
      }
    }
  };

  // 网站配置
  const sites = [
    {
      id: '91p',
      name: '91PORNY九色',
      logo: (isSelected) => (
        <div className="flex flex-col items-center justify-center">
          <span className={`font-bold text-lg ${isSelected ? 'text-white' : 'text-gray-700'}`}>91</span>
          <span className={`font-bold text-xs ${isSelected ? 'text-white' : 'text-red-500'}`}>PORNY</span>
          <span className={`font-bold text-xs px-1 rounded ${isSelected ? 'bg-white text-red-500' : 'bg-red-500 text-white'}`}>九色</span>
        </div>
      ),
      color: 'bg-red-500'
    },
    {
      id: 'other',
      name: '其他网站',
      logo: (isSelected) => <span className="text-2xl">{isSelected ? '🌐' : '🌐'}</span>,
      color: 'bg-blue-500'
    }
  ];

  useEffect(() => {
    fetchScrapedVideos();
  }, []);

  // 自动清除提示信息
  useEffect(() => {
    if (success || error) {
      const timer = setTimeout(() => {
        setSuccess('');
        setError('');
      }, 5000); // 5秒后自动清除
      return () => clearTimeout(timer);
    }
  }, [success, error]);

  const fetchScrapedVideos = async () => {
    try {
      const response = await api.get('/admin/scraped');
      setScrapedVideos(response.data.scraped_videos);
    } catch (error) {
      console.error('Error fetching scraped videos:', error);
    }
  };

  const handleScrape = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');

    try {
      await api.post('/admin/scrape', { 
        url, 
        site: selectedSite 
      });
      setSuccess('视频信息抓取成功！请在下方查看抓取结果。');
      setUrl('');
      fetchScrapedVideos();
    } catch (error) {
      console.error('Error scraping video:', error);
      setError(error.response?.data?.error || '抓取失败，请检查URL是否正确或网络连接');
    } finally {
      setLoading(false);
    }
  };

  const handleImport = async (scrapedId) => {
    try {
      await api.post(`/admin/scraped/${scrapedId}/import`);
      setSuccess('抓取的视频已成功发布到平台！');
      fetchScrapedVideos();
    } catch (error) {
      console.error('Error publishing video:', error);
      setError('发布失败，请检查网络连接后重试');
    }
  };

  const handleReject = async (scrapedId) => {
    setConfirmDialog({
      isOpen: true,
      type: 'danger',
      title: '删除抓取记录',
      message: '确定要删除这个抓取记录吗？此操作不可撤销，删除后将无法恢复抓取的视频信息。',
      onConfirm: async () => {
        try {
          // Delete the scraped video
          await api.delete(`/admin/scraped/${scrapedId}`);
          setSuccess('抓取记录已成功删除！');
          fetchScrapedVideos();
        } catch (error) {
          console.error('Error deleting video:', error);
          setError('删除失败，请重试');
        }
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
      },
      onClose: () => {
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
      }
    });
  };

  const handleSiteChange = (siteId) => {
    setSelectedSite(siteId);
    setError('');
    setSuccess('');
  };

  const handlePreview = (video) => {
    setPreviewVideo(video);
  };

  const closePreview = () => {
    // 清理HLS实例
    if (hlsInstance) {
      hlsInstance.destroy();
      setHlsInstance(null);
    }
    setPreviewVideo(null);
  };

  // 批量选择处理
  const handleSelectVideo = (videoId) => {
    setSelectedVideos(prev => {
      if (prev.includes(videoId)) {
        return prev.filter(id => id !== videoId);
      } else {
        return [...prev, videoId];
      }
    });
  };

  const handleSelectAll = () => {
    if (selectAll) {
      setSelectedVideos([]);
      setSelectAll(false);
    } else {
      const pendingVideos = scrapedVideos.filter(video => video.status === 'pending').map(video => video.id);
      setSelectedVideos(pendingVideos);
      setSelectAll(true);
    }
  };

  const handleBatchPublish = () => {
    if (selectedVideos.length === 0) {
      setError('请先选择要发布的视频');
      return;
    }

    setConfirmDialog({
      isOpen: true,
      type: 'warning',
      title: '批量发布视频',
      message: `确定要发布选中的 ${selectedVideos.length} 个视频吗？`,
      onConfirm: async () => {
        try {
          const response = await api.post('/admin/scraped/batch-publish', {
            video_ids: selectedVideos
          });

          setSuccess(response.data.message || `成功发布 ${response.data.success_count} 个视频！`);
          setSelectedVideos([]);
          setSelectAll(false);
          fetchScrapedVideos();
        } catch (error) {
          console.error('Error batch publishing:', error);
          setError('批量发布失败：' + (error.response?.data?.error || error.message));
        }
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
      }
    });
  };

  const handleBatchDelete = () => {
    if (selectedVideos.length === 0) {
      setError('请先选择要删除的视频');
      return;
    }

    setConfirmDialog({
      isOpen: true,
      type: 'danger',
      title: '批量删除视频',
      message: `确定要删除选中的 ${selectedVideos.length} 个抓取记录吗？此操作不可撤销！`,
      onConfirm: async () => {
        try {
          const response = await api.post('/admin/scraped/batch-delete', {
            video_ids: selectedVideos
          });

          setSuccess(response.data.message || `成功删除 ${response.data.success_count} 个抓取记录！`);
          setSelectedVideos([]);
          setSelectAll(false);
          fetchScrapedVideos();
        } catch (error) {
          console.error('Error batch deleting:', error);
          setError('批量删除失败：' + (error.response?.data?.error || error.message));
        }
        setConfirmDialog(prev => ({ ...prev, isOpen: false }));
      }
    });
  };

  const getStatusBadge = (status) => {
    const styles = {
      pending: 'bg-yellow-100 text-yellow-800',
      published: 'bg-green-100 text-green-800',
      deleted: 'bg-red-100 text-red-800'
    };

    const labels = {
      pending: '待处理',
      published: '已发布',
      deleted: '已删除'
    };

    return (
      <span className={`px-2 py-1 text-xs font-medium rounded-full ${styles[status] || 'bg-gray-100 text-gray-800'}`}>
        {labels[status] || status}
