                            onClick={() => handleImport(video.id)}
                            className="px-3 py-1.5 bg-green-600 text-white text-sm rounded-lg hover:bg-green-700 transition-colors"
                          >
                            发布视频
                          </button>
                          <button
                            onClick={() => handleReject(video.id)}
                            className="px-3 py-1.5 bg-red-600 text-white text-sm rounded-lg hover:bg-red-700 transition-colors"
                          >
                            删除记录
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-16">
              <svg className="w-16 h-16 text-gray-300 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
              </svg>
              <h3 className="text-lg font-medium text-gray-900 mb-2">暂无抓取记录</h3>
              <p className="text-gray-500">输入视频页面URL开始抓取</p>
            </div>
          )}
        </div>
          </div>
        </div>
      </div>

      {/* Confirm Dialog */}
      <ConfirmDialog
        isOpen={confirmDialog.isOpen}
        type={confirmDialog.type}
        title={confirmDialog.title}
        message={confirmDialog.message}
        onConfirm={confirmDialog.onConfirm}
        onClose={confirmDialog.onClose || (() => setConfirmDialog(prev => ({ ...prev, isOpen: false })))}
      />

      {/* Video Preview Modal */}
      {previewVideo && (
        <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl max-w-4xl max-h-[90vh] w-full overflow-hidden">
            <div className="p-6 border-b border-gray-200">
              <div className="flex items-center justify-between">
                <h3 className="text-xl font-semibold text-gray-900">视频预览</h3>
                <div className="flex items-center space-x-2">
                  <button
                    onClick={closePreview}
                    className="text-gray-400 hover:text-gray-600 transition-colors"
                  >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              </div>
            </div>

            <div className="p-6">
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* 左侧：视频预览 */}
                <div className="lg:col-span-1">
                  <h4 className="text-sm font-semibold text-gray-900 mb-3">视频预览</h4>
                  <div className="relative aspect-video bg-gray-900 rounded-lg overflow-hidden border border-gray-200">
                    {previewVideo.video_url ? (
                      <>
                        {/* 检测是否是iframe格式 */}
                        {previewVideo.video_url.includes('<iframe') ? (
                          // 从iframe标签中提取src并渲染
                          (() => {
                            const srcMatch = previewVideo.video_url.match(/src=['"](.*?)['"]/)
                            const iframeSrc = srcMatch ? srcMatch[1] : ''
                            return iframeSrc ? (
                              <iframe
                                key={previewVideo.id}
                                src={iframeSrc}
                                title={previewVideo.title}
                                className="w-full h-full"
                                frameBorder="0"
                                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                                allowFullScreen
                              ></iframe>
                            ) : (
                              <div className="w-full h-full bg-gray-800 flex items-center justify-center">
                                <span className="text-gray-400 text-xs">无效的iframe代码</span>
                              </div>
