                          })()
                        ) : (
                          // video标签形式（mp4或m3u8）
                          <video
                            id="preview-video"
                            key={previewVideo.id}
                            controls
                            autoPlay
                            muted
                            preload="metadata"
                            className="w-full h-full object-contain"
                            onError={(e) => {
                              console.error('Video error:', e);
                            }}
                          >
                            {previewVideo.video_url.includes('.m3u8') ? (
                              <span>加载中...</span>
                            ) : (
                              <source src={previewVideo.video_url} type="video/mp4" />
