                          </video>
                        )}
                      </>
                    ) : previewVideo.cover_url ? (
                      <img
                        src={previewVideo.cover_url}
                        alt={previewVideo.title}
                        className="w-full h-full object-cover"
                        onError={(e) => {
                          e.target.onerror = null;
                          e.target.style.display = 'none';
                        }}
                      />
                    ) : (
                      <div className="w-full h-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center">
                        <svg className="w-12 h-12 text-white/50" fill="currentColor" viewBox="0 0 20 20">
                          <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                        </svg>
                      </div>
                    )}
                  </div>
                </div>

                {/* 右侧：视频信息 */}
                <div className="lg:col-span-2">
                  <h4 className="text-sm font-semibold text-gray-900 mb-3">视频信息</h4>
                  <div className="space-y-4">
                    {/* 标题 */}
                    <div>
                      <label className="text-xs font-medium text-gray-600 mb-1 block">标题</label>
                      <p className="text-sm text-gray-900 bg-gray-50 rounded px-3 py-2 border border-gray-200 break-words">
                        {previewVideo.title || '无标题'}
                      </p>
                    </div>

                    {/* 描述 */}
                    <div>
                      <label className="text-xs font-medium text-gray-600 mb-1 block">描述</label>
                      <p className="text-sm text-gray-800 bg-gray-50 rounded px-3 py-2 border border-gray-200 max-h-24 overflow-y-auto break-words whitespace-pre-wrap">
                        {previewVideo.description || '无描述'}
                      </p>
                    </div>

                    {/* 来源URL */}
                    <div>
                      <label className="text-xs font-medium text-gray-600 mb-1 block">来源URL</label>
                      <a 
                        href={previewVideo.source_url} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-xs text-blue-600 hover:text-blue-800 hover:underline bg-blue-50 rounded px-3 py-2 block break-all border border-blue-200 overflow-hidden"
                      >
                        {previewVideo.source_url}
                      </a>
                    </div>

                    {/* 嵌入代码 */}
                    <div>
                      <label className="text-xs font-medium text-gray-600 mb-1 block">嵌入代码</label>
                      <div className="bg-gray-900 rounded px-3 py-2 border border-gray-700 max-h-32 overflow-y-auto">
                        <p className="text-xs text-green-400 font-mono break-all whitespace-pre-wrap tracking-tight">
                          {previewVideo.video_url || '未提取到嵌入代码'}
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminScraper;
